import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"AI 编程的底层原则","description":"","frontmatter":{"title":"AI 编程的底层原则","author":"[@SaitoWu](https://x.com/SaitoWu) (Saito)","date":"2026-05-09T00:00:00.000Z","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-09-@SaitoWu-851216.md","filePath":"research/tweets/2026-05-09-@SaitoWu-851216.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-05-09-@SaitoWu-851216.md"};function i(l,t,p,n,d,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="ai-编程的底层原则" tabindex="-1">AI 编程的底层原则 <a class="header-anchor" href="#ai-编程的底层原则" aria-label="Permalink to &quot;AI 编程的底层原则&quot;">​</a></h1><blockquote><p><strong>作者</strong>: <a href="https://x.com/SaitoWu" target="_blank" rel="noreferrer">@SaitoWu</a> (Saito)<br><strong>原文</strong>: <a href="https://x.com/SaitoWu/status/2053101671035851216" target="_blank" rel="noreferrer">https://x.com/SaitoWu/status/2053101671035851216</a><br><strong>發布日期</strong>: 2026-05-09<br><strong>類型</strong>: Twitter Article<br><strong>統計</strong>: 👍 189 · 🔁 33 · 🔖 437 · 👁 31,980</p></blockquote><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>AI 時代軟體工程基礎知識比以往更重要——壞代碼在 AI 加持下熵爆炸更快，工程師的核心職責從「寫代碼」轉向「守住設計邊界」。</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Matt Pocock 怒怼「Specs-to-Code」：AI 时代，软件基础比任何时候都更重要</p><p>刚刷完 Matt Pocock 这场演讲，标题叫 《Claude Code for Real Engineers》，直接把很多人的焦虑干碎了。</p><p>他一句话总结就是：软件工程的基础知识，现在比以往任何时候都更值钱。</p><p>不是因为 AI 要取代你，而是因为坏代码在 AI 时代变得前所未有地昂贵。他把「specs-to-code」「只改 spec 不看代码」这些流行玩法，直接批成了 vibe coding 的另一种形式。然后用一整套非常老派、但极其有效的软件工程方法告诉你：怎么把 Claude Code 这类 AI 工具，真正用成工程师的 10 倍放大器，而不是一个越写越乱的代码老虎机。</p><p>这场演讲最反常识的地方在于：大家都以为 AI 让代码变便宜了，但 Matt 说，真正变贵的恰恰是坏代码。</p><h2 id="坏代码-在-ai-时代反而更贵了" tabindex="-1">坏代码，在 AI 时代反而更贵了 <a class="header-anchor" href="#坏代码-在-ai-时代反而更贵了" aria-label="Permalink to &quot;坏代码，在 AI 时代反而更贵了&quot;">​</a></h2><p>现在很多人都在喊：「代码已经便宜了，用 AI 随便生成就行。」</p><p>Matt 直接反驳：错。Code is NOT cheap。坏代码现在是最贵的。</p><p>为什么？因为在一个好的代码库里，AI 能真正发挥 10 倍效率；但在一个烂代码库里，AI 只会越写越烂，最后 entropy（熵）爆炸。</p><p>他自己亲测过 specs-to-code 模式：第一次生成代码还行，第二次质量开始变差，第三次直接垃圾。原因也很简单，每次只改 spec，不关注整体设计，代码结构就会越来越复杂。到最后，AI 根本看不懂自己在改什么，只能在混乱上继续叠混乱。</p><p>所以 AI 时代不是可以忽略代码，而是必须把代码写得比以前更好。只有好的代码库，才能真正吃到 AI 的红利。</p><h2 id="ai-没理解你-是因为你们没有共享蓝图" tabindex="-1">AI 没理解你，是因为你们没有共享蓝图 <a class="header-anchor" href="#ai-没理解你-是因为你们没有共享蓝图" aria-label="Permalink to &quot;AI 没理解你，是因为你们没有共享蓝图&quot;">​</a></h2><p>最常见的问题是：你脑子里有一个很清晰的 idea，但 AI 做出来的东西完全不是那回事。</p><p>Matt 说，这是经典的 design concept 缺失。这个概念来自 Frederick P. Brooks 的《The Design of Design》。你和 AI 之间没有共享的「设计概念」，就像两个人在设计同一栋房子，但根本没对齐蓝图。</p><p>所以他的第一个实操技能叫 Grill Me。</p><p>这个 skill 在 GitHub 已经有 13k+ stars，核心 prompt 就两句：</p><blockquote><p>Interview me relentlessly about every aspect of this plan until we reach a shared understanding. Walk down each branch of the design tree, resolving dependencies between decisions one by one.</p></blockquote><p>意思很简单：让 AI 不要急着写代码，而是先疯狂追问你，直到你们对这个需求建立共同理解。</p><p>AI 会问你 40 到 100 个问题，把需求树上的每个分支都走一遍。Matt 说，这比 Claude Code 默认的 Plan Mode 好很多，因为 Plan Mode 太急着产出东西，而 Grill Me 先做最重要的事：把概念对齐。</p><p>他的建议是，把这段对话记录直接转成 PRD 或 issues，然后再交给 AFK agent 接着干。</p><h2 id="让-ai-少废话-先统一语言" tabindex="-1">让 AI 少废话，先统一语言 <a class="header-anchor" href="#让-ai-少废话-先统一语言" aria-label="Permalink to &quot;让 AI 少废话，先统一语言&quot;">​</a></h2><p>第二个问题是：AI 输出又长又绕，你看着累，它自己也容易跑偏。</p><p>Matt 搬出了领域驱动设计 DDD 里的一个核心概念：Ubiquitous Language，通用语言。</p><p>也就是你、团队、代码库、AI，都应该使用同一套词汇。否则你说的是「用户」，AI 理解成「账户」；你说的是「订阅」，AI 理解成「订单」；你说的是「workspace」，它可能在代码里到处找 project、team、org，最后越改越乱。</p><p>他的实操技能叫 Ubiquitous Language Skill。</p><p>做法是让 AI 先扫描整个代码库，提取所有术语，然后做成一个 Markdown 表格：术语、定义、使用场景。之后所有 prompt 都带上这个文件，强迫 AI 和你使用同一套语言。</p><p>效果非常明显：AI 的思考痕迹会变短，实现会更精准，啰嗦程度也会大幅下降。Matt 说这个方法简直是 powerhouse，他自己一直开着这个文件，用在 Grill 和 planning 过程中。</p><h2 id="ai-写不出能跑的代码-本质是反馈太慢" tabindex="-1">AI 写不出能跑的代码，本质是反馈太慢 <a class="header-anchor" href="#ai-写不出能跑的代码-本质是反馈太慢" aria-label="Permalink to &quot;AI 写不出能跑的代码，本质是反馈太慢&quot;">​</a></h2><p>第三个问题更现实：AI 写了一大坨代码，但根本跑不通。</p><p>Matt 认为，核心原因不是 AI 不够聪明，而是反馈循环不够强。他推荐三板斧：静态类型、浏览器访问权限、自动化测试。</p><p>但问题是，AI 默认不会好好使用这些反馈。它很喜欢一次写一大坨代码，然后才想起来跑 type check。等它发现错了，错误已经叠了几十层，修起来就像拆炸弹。</p><p>Matt 提到一个很反常识的观点：速率限制，本质上就是反馈速率。</p><p>这个思想来自《The Pragmatic Programmer》。开得太快，就一定会撞车。所以他的实操建议是：强制 TDD。</p><p>先写测试，让测试通过，再重构代码。TDD 会逼 AI 每次只走一小步，天然匹配 small, deliberate steps。这比让 AI 一口气写完整个功能可靠得多。</p><h2 id="真正适合-ai-的代码-不是更多模块-而是更深模块" tabindex="-1">真正适合 AI 的代码，不是更多模块，而是更深模块 <a class="header-anchor" href="#真正适合-ai-的代码-不是更多模块-而是更深模块" aria-label="Permalink to &quot;真正适合 AI 的代码，不是更多模块，而是更深模块&quot;">​</a></h2><p>这可能是整场演讲最硬核的部分。</p><p>Matt 引用了 John Ousterhout 的《A Philosophy of Software Design》。这里有一个非常重要的判断标准：坏代码 = 很多浅模块；好代码 = 少量深模块。</p><p>什么是 shallow modules？就是功能很少，但接口很复杂。AI 遇到这种代码，就像在迷宫里乱窜，每个模块都要理解一堆细节，一不小心就改崩。</p><p>什么是 deep modules？就是功能很多，但接口极简。复杂性被藏在模块内部，外部只暴露简单、稳定的接口。</p><p>AI 最喜欢这种结构。因为它只需要理解接口，就能安全地修改实现。</p><p>所以 Matt 的另一个实操技能叫 Improve Codebase Architecture。步骤很清晰：先扫描代码库，找到相关代码块；然后把它们封装成一个深模块；接着设计一个简单接口，这一步必须由你亲自把关；最后，具体实现细节可以交给 AI。</p><p>这个 skill 可以重复使用，把代码库里一堆浅模块，逐步重构成深模块。</p><h2 id="你的工作不是写更多代码-而是守住设计边界" tabindex="-1">你的工作不是写更多代码，而是守住设计边界 <a class="header-anchor" href="#你的工作不是写更多代码-而是守住设计边界" aria-label="Permalink to &quot;你的工作不是写更多代码，而是守住设计边界&quot;">​</a></h2><p>很多工程师现在最大的压力是：AI 出代码太快了，大脑跟不上。</p><p>Matt 的解决方案是：把模块当成灰盒。</p><p>你不需要盯着每一行实现细节。你真正要做的是设计接口、定义目的、写测试边界、把关键模块边界守住。至于非核心模块内部怎么实现，可以大胆交给 AI。</p><p>这样你的大脑负担会大幅降低，同时还能保持对整体设计的掌控。</p><p>他还引用了 Kent Beck 的一句话：每天都要投资系统设计。</p><p>而 specs-to-code 最大的问题，恰恰是反过来。它是在 divest from design，也就是放弃设计。所以越跑越崩。</p><h2 id="一套普通工程师可以直接抄的-ai-编程工作流" tabindex="-1">一套普通工程师可以直接抄的 AI 编程工作流 <a class="header-anchor" href="#一套普通工程师可以直接抄的-ai-编程工作流" aria-label="Permalink to &quot;一套普通工程师可以直接抄的 AI 编程工作流&quot;">​</a></h2><p>新需求来了，不要立刻让 AI 写代码。先用 Grill Me 建立 shared design concept，让 AI 把你脑子里的模糊想法追问清楚。</p><p>接着生成 Ubiquitous Language 文件，让 AI、你、代码库使用同一套语言。之后所有 prompt 都带上它，减少误解和废话。</p><p>然后用 TDD 模式 写代码，先测试，再实现。不要让 AI 一口气写一大坨，而是让它每一步都接受反馈。</p><p>同时，定期运行 Improve Codebase Architecture，把浅模块逐步重构成深模块。重要接口自己把关，实现细节大胆委托给 AI。</p><p>最后，每天花时间思考模块边界和系统设计，而不是只盯着写代码。</p><p>Matt 自己就是用这些 skill，把 Claude Code 玩成了真正的工程师工具，而不是 vibe coding 玩具。</p><h2 id="这场演讲最狠的几句话" tabindex="-1">这场演讲最狠的几句话 <a class="header-anchor" href="#这场演讲最狠的几句话" aria-label="Permalink to &quot;这场演讲最狠的几句话&quot;">​</a></h2><p><strong>Specs-to-code 不是未来，它只是另一种 vibe coding。</strong></p><p><strong>坏代码在 AI 时代比以前更贵，因为它会把 AI 的能力也一起废掉。</strong></p><p><strong>AI 是地面上的战术士兵，你才是战略指挥官。</strong></p><p><strong>软件基础知识，尤其是设计、模块化、测试，现在比 20 年前更重要。</strong></p><h2 id="最后真正让人安心的-不是-ai-变强了-而是基础知识还值钱" tabindex="-1">最后真正让人安心的，不是 AI 变强了，而是基础知识还值钱 <a class="header-anchor" href="#最后真正让人安心的-不是-ai-变强了-而是基础知识还值钱" aria-label="Permalink to &quot;最后真正让人安心的，不是 AI 变强了，而是基础知识还值钱&quot;">​</a></h2><p>AI 没有让代码变得不重要。恰恰相反，它让「写好代码」这件事变得前所未有地关键。</p><p>你越懂老派软件工程，越懂 Ousterhout、Brooks、DDD、TDD，AI 就越能为你所用。你越偷懒，只想改 spec、不看代码，代码库就越快崩成一团垃圾。</p><p>Matt Pocock 这场演讲，其实是给所有还在焦虑「AI 会不会抢饭碗」的工程师打了一针强心剂：</p><p><strong>你的基础知识，现在是稀缺资源。</strong></p><p>想直接抄作业的同学，可以去 GitHub 搜 <a href="https://github.com/mattpocock/skills" target="_blank" rel="noreferrer">MattPocockSkills</a>。里面有他提到的所有 skill：Grill Me、Ubiquitous Language、Improve Codebase Architecture。</p><p>他也在 AIhero.dev 写 newsletter，YouTube 和 Twitter 都持续更新。</p><p>完整演讲逐字稿，可以在 <a href="https://podwise.ai/dashboard/episodes/7846761" target="_blank" rel="noreferrer">Podwise</a> 免费获取。</p><hr><h2 id="深度分析" tabindex="-1">深度分析 <a class="header-anchor" href="#深度分析" aria-label="Permalink to &quot;深度分析&quot;">​</a></h2><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>壞代碼 AI 時代更貴</strong>：在好代碼庫 AI 發揮 10x；在爛代碼庫 AI 只會疊加混亂，entropy 爆炸</li><li><strong>Grill Me 技術</strong>：先建立 shared design concept（40-100 問），再寫代碼；比 Plan Mode 更重要的是概念對齊</li><li><strong>Ubiquitous Language</strong>：掃描代碼庫提取術語→Markdown 表格→每個 prompt 帶上，縮短 AI 思考痕跡、提升精準度</li><li><strong>TDD 強制反饋循環</strong>：速率限制 = 反饋速率，強制 small deliberate steps 避免錯誤疊加</li><li><strong>深模組 vs 淺模組</strong>：Deep modules（功能多+接口極簡）是 AI 友好結構；工程師職責是守住接口邊界，把實現交給 AI</li></ol><h3 id="關鍵數據-工具-引用" tabindex="-1">關鍵數據 / 工具 / 引用 <a class="header-anchor" href="#關鍵數據-工具-引用" aria-label="Permalink to &quot;關鍵數據 / 工具 / 引用&quot;">​</a></h3><ul><li><strong>GitHub</strong>: <a href="https://github.com/mattpocock/skills%EF%BC%8813k+" target="_blank" rel="noreferrer">https://github.com/mattpocock/skills（13k+</a> stars）</li><li><strong>書籍引用</strong>：Brooks《The Design of Design》、Ousterhout《A Philosophy of Software Design》、《The Pragmatic Programmer》</li><li><strong>Kent Beck</strong>：每天都要投資系統設計</li><li><strong>Specs-to-code 親測</strong>：第 1 次 OK → 第 2 次差 → 第 3 次垃圾（質量線性遞降）</li><li><strong>Podwise 逐字稿</strong>：<a href="https://podwise.ai/dashboard/episodes/7846761" target="_blank" rel="noreferrer">https://podwise.ai/dashboard/episodes/7846761</a></li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>論點缺乏量化</strong>：「10x 效率」「40-100 個問題」等說法無 benchmark 佐證，主要是定性觀察，可重現性待驗證</li><li><strong>Grill Me vs Plan Mode 對比過度簡化</strong>：稱 Plan Mode「太急著產出」但未說明具體測試條件，這個結論對不同任務類型可能有差異</li><li><strong>深模組原則的實踐難度被低估</strong>：如何判斷「接口夠簡」需要豐富設計經驗，初階工程師可能難以拿捏邊界</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>3 個 Skill 有具體 prompt 或步驟可直接套用；GitHub repo 可參照</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>Grill Me、Ubiquitous Language 是具體新工具；深模組框架應用到 AI coding 有力，但「好代碼重要」整體論點通用</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>親測觀察 + 書籍引用 + 13k stars 社群驗證，但缺乏量化 benchmark</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>各 skill 有完整步驟；TDD + 靜態類型三板斧明確；Improve Codebase Architecture 流程清晰</td></tr><tr><td>E. 泛化性</td><td>9/10</td><td>適用任何 AI coding 工具，跨技術棧；DDD、TDD、深模組均為通用原則</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.05/10</strong></td><td>9×0.3 + 7×0.2 + 7×0.2 + 8×0.15 + 9×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：SKILL（核心是靜態提示詞/方法論）<br><strong>整合位置</strong>：可參照 <a href="https://github.com/mattpocock/skills" target="_blank" rel="noreferrer">https://github.com/mattpocock/skills</a> 實作 <code>grill-me</code>、<code>ubiquitous-language</code> 兩個 skill<br><strong>整合狀態</strong>：待實作</p>',88)])])}const g=e(s,[["render",i]]);export{u as __pageData,g as default};
